// === Máquina de Estado JUREMA ===
// Referência: plan file + processTurn.md

const ctx = $('Merge Contexto').item.json;
const pacResp = $('Buscar Paciente').item.json;
const sessResp = $('Buscar Sessão').item.json;

const paciente = (Array.isArray(pacResp.body) ? pacResp.body : [])[0] || null;
const sessao = (Array.isArray(sessResp.body) ? sessResp.body : [])[0] || null;

const wa_id = ctx.wa_id;
const texto = (ctx.texto || '').toLowerCase();
const texto_original = ctx.texto_original || '';
const interactive_id = ctx.interactive_id || null;
const interactive_title = ctx.interactive_title || null;

// --- Gatilho de início ---
const disparou = texto === 'teleconsultoria';

function resp(tipo, mensagem, extra = {}) {
  return [{ json: { wa_id, ignorar: false, tipo_resposta: tipo, mensagem, ...extra } }];
}

const OPCOES_ESPECIALIDADES = [
  { id: 'medico',            title: 'Médica(o)' },
  { id: 'psicologo',         title: 'Psicóloga(o)' },
  { id: 'nutricao',          title: 'Nutricionista' },
  { id: 'assistente_social', title: 'Assistente Social' }
];

// Se não tem sessão e não disparou "teleconsultoria", ignora
if (!sessao && !disparou) {
  return [{ json: { wa_id, ignorar: true, motivo: 'sem_sessao_sem_gatilho' } }];
}

// Dados de trabalho (buffer da sessão)
const dados = {
  wa_id,
  step:          sessao?.step          || 'inicio',
  primeiro_nome: sessao?.primeiro_nome || paciente?.primeiro_nome || null,
  ultimo_nome:   sessao?.ultimo_nome   || paciente?.ultimo_nome   || null,
  cpf:           sessao?.cpf           || paciente?.cpf           || null,
  hospital:      sessao?.hospital      || paciente?.hospital      || null,
  especialidade: sessao?.especialidade || null,
  modalidade:    sessao?.modalidade    || null
};

// --- Gatilho inicial ---
if (disparou) {
  if (paciente) {
    dados.step = 'aguardando_especialidade';
    return resp('lista', `Olá, *${paciente.primeiro_nome}*! Qual especialidade você precisa?`, {
      list_rows: OPCOES_ESPECIALIDADES,
      list_button: 'Escolher',
      dados_sessao: dados, concluido: false
    });
  } else {
    dados.step = 'aguardando_primeiro_nome';
    return resp('texto',
      'Olá! Bem-vindo(a) à Teleconsultoria IMIP 😊\n\nPara começar, me informe seu *primeiro nome*.',
      { dados_sessao: dados, concluido: false }
    );
  }
}

// --- Máquina de estado (sessão ativa) ---
const step = dados.step;

if (step === 'aguardando_primeiro_nome') {
  dados.primeiro_nome = texto_original.trim();
  dados.step = 'aguardando_ultimo_nome';
  return resp('texto', 'Agora me informa seu *último nome*.', { dados_sessao: dados, concluido: false });
}

if (step === 'aguardando_ultimo_nome') {
  dados.ultimo_nome = texto_original.trim();
  dados.step = 'aguardando_cpf';
  return resp('texto', `*${dados.primeiro_nome}*, me informa apenas os números do seu *CPF*.`, { dados_sessao: dados, concluido: false });
}

if (step === 'aguardando_cpf') {
  dados.cpf = (texto_original || '').replace(/\D/g, '');
  dados.step = 'aguardando_hospital';
  return resp('texto', `Obrigada *${dados.primeiro_nome}*! Em qual *Hospital* você trabalha?`, { dados_sessao: dados, concluido: false });
}

if (step === 'aguardando_hospital') {
  dados.hospital = texto_original.trim();
  dados.step = 'aguardando_especialidade';
  return resp('lista', 'Qual especialidade você precisa?', {
    list_rows: OPCOES_ESPECIALIDADES,
    list_button: 'Escolher',
    dados_sessao: dados, concluido: false
  });
}

if (step === 'aguardando_especialidade') {
  const esp = interactive_id || '';
  const validos = OPCOES_ESPECIALIDADES.map(o => o.id);
  if (!validos.includes(esp)) {
    return resp('lista', 'Por favor, escolha uma das opções abaixo.', {
      list_rows: OPCOES_ESPECIALIDADES, list_button: 'Escolher',
      dados_sessao: dados, concluido: false
    });
  }
  dados.especialidade = esp;
  dados.step = 'aguardando_modalidade';
  return resp('botoes', 'Como você prefere o atendimento?', {
    buttons: [
      { id: 'teleatendimento', title: 'Teleatendimento' },
      { id: 'texto',           title: 'Enviar texto' }
    ],
    dados_sessao: dados, concluido: false
  });
}

if (step === 'aguardando_modalidade') {
  const mod = interactive_id || '';
  if (!['teleatendimento','texto'].includes(mod)) {
    return resp('botoes', 'Por favor, escolha uma das opções.', {
      buttons: [
        { id: 'teleatendimento', title: 'Teleatendimento' },
        { id: 'texto',           title: 'Enviar texto' }
      ],
      dados_sessao: dados, concluido: false
    });
  }
  dados.modalidade = mod;
  dados.step = 'concluido';

  const mensagem_final = mod === 'teleatendimento'
    ? 'Perfeito! Uma atendente entrará em contato para confirmar o *link, data e horário* da videochamada. 🎥'
    : 'Perfeito! Envie agora sua *dúvida* em uma mensagem. Um(a) profissional responderá em até 72h. 🕐';

  const esp_label = (OPCOES_ESPECIALIDADES.find(o => o.id === dados.especialidade) || {}).title || dados.especialidade;

  return resp('texto', mensagem_final, {
    dados_sessao: dados,
    concluido: true,
    paciente_upsert: {
      wa_id,
      primeiro_nome: dados.primeiro_nome,
      ultimo_nome:   dados.ultimo_nome,
      cpf:           dados.cpf,
      hospital:      dados.hospital
    },
    criar_conversa: mod === 'texto',
    criar_solicitacao: true,
    msg_equipe: `🔔 *Nova solicitação JUREMA*\n\n👤 ${dados.primeiro_nome} ${dados.ultimo_nome}\n📱 ${wa_id}\n🪪 ${dados.cpf}\n🏥 ${dados.hospital}\n🩺 ${esp_label}\n📞 ${mod === 'teleatendimento' ? 'Teleatendimento (videochamada)' : 'Texto (72h)'}`
  });
}

return [{ json: { wa_id, ignorar: true, motivo: 'step_desconhecido', step } }];

const d = $json;
const base = { recipient_type: 'individual', to: d.wa_id };

let payload;
if (d.tipo_resposta === 'botoes') {
  payload = {
    ...base,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: { text: d.mensagem },
      action: { buttons: (d.buttons || []).slice(0, 3).map(b => ({ type: 'reply', reply: { id: b.id, title: b.title } })) }
    }
  };
} else if (d.tipo_resposta === 'lista') {
  payload = {
    ...base,
    type: 'interactive',
    interactive: {
      type: 'list',
      body: { text: d.mensagem },
      action: {
        button: d.list_button || 'Ver opções',
        sections: [{ title: 'Opções', rows: d.list_rows || [] }]
      }
    }
  };
} else {
  payload = { ...base, type: 'text', text: { body: d.mensagem } };
}

return [{ json: { ...d, turn_payload: payload } }];

const pacResp = $input.first().json;
const paciente = (Array.isArray(pacResp.body) ? pacResp.body : [])[0] || null;
const preserved = $('Preservar Dados').item.json;
return [{ json: { ...preserved, paciente_id: paciente?.id, paciente } }];

